import math

class BehavioralFinanceAI:
    def evaluate_herd_mentality(self, asset_price_momentum: float, social_buzz_score: float) -> float:
        """Sürü psikolojisi yoğunluk puanı."""
        return (asset_price_momentum * 0.4) + (social_buzz_score * 0.6)

